class NidocaAccordionItem extends LitElement {
    constructor() {
        super(...arguments);
        this.header = '';
        this.opened = false;
    }
    render() {
        return html `
      <div @click="${() => this.toggle()}" class="header">
        <nidoca-text text="${this.header}"></nidoca-text>
        <nidoca-icon icon="${this.opened ? 'keyboard_arrow_down' : 'keyboard_arrow_up'}"></nidoca-icon>
      </div>
      ${this.opened ? html ` <slot></slot>` : html ``}
    `;
    }
    toggle() {
        console.log('accordion clicked, state=' + this.opened);
        this.opened = Boolean(!this.opened);
        console.log('accordion clicked, after state=' + this.opened);
        this.dispatchEvent(new CustomEvent('nidoca-event-accordion-item-clicked', { detail: this, bubbles: true, composed: true }));
    }
}

class NidocaAccordion extends LitElement {
    constructor() {
        super(...arguments);
        this.theme = NidocaTheme.SURFACE;
        this.accordionType = AccordionType.SINGLE;
    }
    render() {
        return html `
      ${NidocaTheme.getStyle(this.theme)}
      <slot
        @nidoca-event-accordion-item-clicked="${(event) => this.accordionSwitched(event)}"
        id="accordionSlot"
      ></slot>
    `;
    }
    accordionSwitched(event) {
        const accordionItemComponent = event.detail;
        switch (this.accordionType) {
            case AccordionType.SINGLE:
                if (this.accordionSlot != null) {
                    const assignedElements = this.accordionSlot.assignedElements();
                    for (let index = 0; index < assignedElements.length; index++) {
                        const element = assignedElements[index];
                        if (element instanceof NidocaAccordionItem && element != accordionItemComponent) {
                            element.opened = false;
                        }
                    }
                }
                break;
            case AccordionType.MULTI:
                break;
        }
        event.stopPropagation();
    }
}

