class NidocaSection extends LitElement {
    constructor() {
        super(...arguments);
        this.flexBasis = 'auto';
    }
    render() {
        return html `
      <style>
        .item,
        ::slotted(.item) {
          flex-basis: ${this.flexBasis};
        }
      </style>
      <slot id="container" class="container" @slotchange="${(event) => this.slotChanged(event)}"></slot>
    `;
    }
    slotChanged(event) {
        const slotElement = event.target;
        const slotWidth = slotElement.offsetWidth;
        const elements = slotElement.assignedElements();
        const elementSize = elements.length;
        const modifyElements = [];
        let elementWidths = 0;
        for (let index = 0; index < elementSize; index++) {
            const element = elements[index];
            element.setAttribute('class', 'item');
            if (element instanceof HTMLElement) {
                const elementWidthStyle = element.style.width;
                if (elementWidthStyle.length == 0) {
                    modifyElements.push(element);
                }
                else {
                    const elementWidthToUpperCase = elementWidthStyle.toUpperCase();
                    const elementWidth = elementWidthToUpperCase.indexOf('PX') > -1
                        ? Number(elementWidthToUpperCase.replace('PX', ''))
                        : (Number(elementWidthToUpperCase.replace('%', '')) / 100) * slotWidth;
                    elementWidths += elementWidth;
                }
            }
        }
        let calculationPercent = 100;
        if (elementWidths > 0) {
            calculationPercent = 100 - 100 * (elementWidths / slotWidth);
        }
        if (calculationPercent == 0) {
            calculationPercent = 100 / elementSize;
        }
        this.flexBasis = String(calculationPercent / modifyElements.length) + '%';
        this.requestUpdate();
    }
}

