class NidocaWizardStep extends LitElement {
    constructor() {
        super(...arguments);
        this.icon = '';
        this.primaryText = '';
        this.isLast = false;
        this.first = false;
    }
    render() {
        return html `
      <div
        style="display:flex;flex-direction:row;flex-wrap:nowrap;align-items:flex-start;justify-content:space-evenly;align-content:space-evenly;"
      >
        <div
          style="display:flex;flex-direction:row;flex-wrap:nowrap;align-items:center;justify-content:flex-start;align-content:space-evenly;"
        >
          <nidoca-icon
            icon="${this.icon}"
            .iconShadowType="${NidocaIconShadowType.NONE}"
            .withIconSpace="${false}"
            .round="${true}"
            .clickable="${true}"
            .deactivated="${false}"
            color="${this.determineColor(this.state)}"
            backgroundColor="${this.determineBackgroundColor(this.state)}"
            size="24"
            @nidoca-event-icon-clicked="${() => this.stepClicked()}"
            sizeUnit="px"
          >
          </nidoca-icon>

          ${this.isLast
            ? html ``
            : html `<nidoca-icon color="${this.determineBackgroundColor(this.state)}" icon="label_important">
              </nidoca-icon>`}
        </div>
        <nidoca-text style="width:48px;" text="${this.primaryText}"><slot></slot> </nidoca-text>
      </div>
    `;
    }
    determineBackgroundColor(state) {
        return state == WizardStepState.COMPLETED
            ? 'var(--app-color-primary)'
            : state == WizardStepState.CURRENT
                ? 'var(--app-color-secondary-background)'
                : 'var(--app-color-surface-background)';
    }
    determineColor(state) {
        return state == WizardStepState.FINISH
            ? 'var(--app-color-success)'
            : state == WizardStepState.COMPLETED
                ? 'var(--mdc-theme-on-primary)'
                : state == WizardStepState.CURRENT
                    ? 'var(--app-color-secondary)'
                    : 'var(--app-color-surface)';
    }
    stepClicked() {
        const customEvent = new CustomEvent('nidoca-event-wizard-step-clicked', {
            detail: this.index,
            bubbles: true,
            composed: true,
        });
        console.debug('dispatch custom event type: %s, detail: %s', customEvent.type, JSON.stringify(customEvent.detail));
        this.dispatchEvent(customEvent);
    }
}

class NidocaWizard extends LitElement {
    render() {
        return html `
      <div
        style="display:flex;flex-direction:row;flex-wrap:nowrap;align-items:flex-start;justify-content:flex-start;align-content:space-evenly;"
        @nidoca-event-wizard-step-clicked="${(event) => this.stepClicked(event)}"
      >
        <slot id="wizardSlot" @slotchange="${(event) => this.slotChanged(event)}"></slot>
      </div>
    `;
    }
    slotChanged(event) {
        const slotElement = event.target;
        if (slotElement == undefined) {
            return;
        }
        const elements = slotElement.assignedElements();
        let selectedStepIndex = 0;
        for (let index = 0; index < elements.length; index++) {
            const element = elements[index];
            if (element instanceof NidocaWizardStep) {
                element.index = index;
                if (element.state == WizardStepState.CURRENT) {
                    selectedStepIndex = index;
                }
                if (element.index == elements.length - 1) {
                    element.isLast = true;
                }
            }
        }
        this.changeState(selectedStepIndex);
    }
    stepClicked(event) {
        const selectedStepIndex = event.detail;
        console.debug('wizard step clicked, selectedStepIndex: %s', selectedStepIndex);
        this.changeState(selectedStepIndex);
    }
    changeState(selectedStepIndex) {
        if (this.wizardSlot) {
            const elements = this.wizardSlot.assignedElements();
            for (let index = 0; index < elements.length; index++) {
                const element = elements[index];
                if (element instanceof NidocaWizardStep) {
                    if (element.index !== undefined) {
                        if (element.index < selectedStepIndex) {
                            element.state = WizardStepState.COMPLETED;
                        }
                        else if (element.index == selectedStepIndex) {
                            element.state = WizardStepState.CURRENT;
                        }
                        else {
                            element.state = WizardStepState.OPEN;
                        }
                    }
                }
            }
        }
    }
}

